import React from "react";

export default function Hero({ data }) {
  const { name, title, subtitle, tagline, contact, stats } = data;

  const [firstName, ...rest] = name.split(" ");
  const lastName = rest.join(" ");

  return (
    <>
      <style>{`
        * {
          box-sizing: border-box;
        }

        body {
          margin: 0;
          overflow-x: hidden;
          background: #05070d;
          color: white;
          font-family: sans-serif;
        }

        .hero {
          min-height: 100vh;
          display: flex;
          justify-content: center;
          align-items: center;
          padding: clamp(60px, 8vw, 120px) 20px;
        }

        .container {
          width: 100%;
          max-width: min(1400px, 92vw);
          margin: auto;
        }

        /* NAME */
        .name {
          font-size: clamp(2rem, 6vw, 6rem);
          font-weight: 800;
          line-height: 1.1;
          word-break: break-word;
          text-align: center;
        }

        .gradient {
          background: linear-gradient(90deg, #00e5ff, #7c3aed);
          -webkit-background-clip: text;
          -webkit-text-fill-color: transparent;
        }

        /* TEXT */
        .sub {
          margin-top: 12px;
          color: #aaa;
          font-size: clamp(1rem, 1.5vw, 1.3rem);
          text-align: center;
        }

        .highlight {
          color: #00e5ff;
        }

        .tag {
          margin-top: 10px;
          color: #888;
          max-width: 650px;
          margin-left: auto;
          margin-right: auto;
          text-align: center;
        }

        /* BUTTONS */
        .btns {
          display: flex;
          flex-direction: column;
          gap: 12px;
          margin-top: 25px;
          width: 100%;
        }

        .btn {
          display: flex;
          align-items: center;
          justify-content: center;  /* 🔥 FIX */
          text-align: center;       /* 🔥 FIX */
          width: 100%;
          padding: 14px 20px;
          border-radius: 999px;
          font-weight: 600;
          text-decoration: none;
          transition: 0.3s;
        }

        .primary {
          background: #00e5ff;
          color: black;
        }

        .primary:hover {
          transform: translateY(-3px);
          box-shadow: 0 10px 30px rgba(0,229,255,0.3);
        }

        .outline {
          border: 1px solid #444;
          color: white;
        }

        .outline:hover {
          border-color: #00e5ff;
          color: #00e5ff;
        }

        /* DESKTOP BUTTON FIX */
        @media (min-width: 768px) {
          .btns {
            flex-direction: row;
            justify-content: center;
          }

          .btn {
            width: auto;
            min-width: 180px;
          }
        }

        /* STATS */
        .stats {
          margin-top: clamp(40px, 5vw, 70px);
          display: grid;
          grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
          gap: clamp(12px, 2vw, 25px);
        }

        /* CARD */
        .card {
          display: flex;
          flex-direction: column;
          justify-content: center;
          align-items: center;   /* 🔥 FIX */
          text-align: center;    /* 🔥 FIX */
          padding: clamp(20px, 2vw, 30px);
          border-radius: 18px;
          background: rgba(255,255,255,0.05);
          border: 1px solid rgba(255,255,255,0.08);
          transition: 0.3s;
        }

        .card:hover {
          transform: translateY(-6px) scale(1.02);
          box-shadow: 0 20px 50px rgba(0,229,255,0.15);
        }

        .value {
          font-size: clamp(1.5rem, 2.5vw, 3rem);
          font-weight: 800;
          color: #00e5ff;
          text-align: center;
          width: 100%;
        }

        .label {
          margin-top: 8px;
          font-size: 0.9rem;
          color: #aaa;
          text-align: center;
          width: 100%;
        }

        /* BIG SCREEN */
        @media (min-width: 1600px) {
          .name {
            font-size: clamp(4rem, 5vw, 7rem);
          }

          .sub {
            font-size: 1.5rem;
          }

          .tag {
            font-size: 1.2rem;
          }
        }

        /* ULTRA BIG (TV) */
        @media (min-width: 2000px) {
          .container {
            max-width: 1600px;
          }
        }
      `}</style>

      <section className="hero">
        <div className="container">

          {/* NAME */}
          <h1 className="name">
            {firstName} <span className="gradient">{lastName}</span>
          </h1>

          {/* SUBTITLE */}
          <p className="sub">
            {title} · <span className="highlight">{subtitle}</span>
          </p>

          {/* TAGLINE */}
          <p className="tag">{tagline}</p>

          {/* BUTTONS */}
          <div className="btns">
            <a href="mailto:your@email.com" className="btn primary">
              Get in Touch
            </a>

            <a
              href={`https://${contact.linkedin}`}
              target="_blank"
              rel="noreferrer"
              className="btn outline"
            >
              LinkedIn
            </a>
          </div>

          {/* STATS */}
          <div className="stats">
            {stats.map((s, i) => (
              <div key={i} className="card">
                <div className="value">{s.value}</div>
                <div className="label">{s.label}</div>
              </div>
            ))}
          </div>

        </div>
      </section>
    </>
  );
}
